style:
.bmr-wrap{font-family:-apple-system,BlinkMacSystemFont,'Inter','Segoe UI',sans-serif;background:#fff;border-radius:16px;overflow:visible;box-shadow:0 8px 40px rgba(15,32,68,.14),0 2px 8px rgba(0,0,0,.06);border:1px solid #dde4f0;position:relative}
.bmr-header{background:linear-gradient(135deg,#0f2044 0%,#1a3a6b 50%,#1e40af 100%);padding:18px 20px;display:flex;justify-content:space-between;align-items:center;gap:12px;flex-wrap:wrap;border-radius:16px 16px 0 0}
.bmr-hl{display:flex;align-items:center;gap:14px}
.bmr-icon{font-size:30px;line-height:1;filter:drop-shadow(0 2px 6px rgba(0,0,0,.35))}
.bmr-title{color:#fff;font-size:17px;font-weight:700;letter-spacing:-.3px;line-height:1.2}
.bmr-sub{color:rgba(255,255,255,.5);font-size:11px;margin-top:3px;letter-spacing:.1px}
.bmr-nav{display:flex;align-items:center;gap:4px;background:rgba(255,255,255,.1);border:1px solid rgba(255,255,255,.18);border-radius:10px;padding:4px 8px}
.bmr-nbtn{background:transparent;border:none;color:rgba(255,255,255,.75);border-radius:7px;width:30px;height:30px;cursor:pointer;font-size:15px;display:flex;align-items:center;justify-content:center;transition:background .15s,color .15s;outline:none;flex-shrink:0}
.bmr-nbtn:hover{background:rgba(255,255,255,.2);color:#fff}
.bmr-nbtn:active{transform:scale(.9)}
.bmr-mlbl{color:#fff;font-size:14px;font-weight:700;min-width:124px;text-align:center;letter-spacing:-.2px;user-select:none}
.bmr-scroll{overflow-x:auto;background:#f8fafc;border-radius:0}
.bmr-scroll::-webkit-scrollbar{height:5px}
.bmr-scroll::-webkit-scrollbar-track{background:#f1f5f9}
.bmr-scroll::-webkit-scrollbar-thumb{background:#c4cfe0;border-radius:4px}
.bmr-table{border-collapse:collapse;font-size:12px;min-width:100%;background:#fff}
.bmr-table thead th{background:#f1f5f9;border-bottom:2px solid #dde4f0;border-right:1px solid #e8edf4;padding:8px 3px 6px;text-align:center;min-width:34px;height:44px;font-weight:600;color:#64748b;font-size:11px}
.bmr-table tbody td{border-bottom:1px solid #f0f4fa;border-right:1px solid #f0f4fa;padding:0;text-align:center;min-width:34px;height:38px}
.bmr-table tbody tr:hover .bmr-rc{background:#eef2ff!important}
.bmr-rc{min-width:90px!important;text-align:left!important;padding:0 12px!important;font-weight:700!important;white-space:nowrap!important;color:#1e293b!important;background:#f8fafc!important;border-right:2px solid #dde4f0!important;font-size:12px!important;position:sticky!important;left:0!important;z-index:1!important}
.bmr-table thead .bmr-rc{z-index:3!important}
.th-today{background:linear-gradient(180deg,#eff6ff,#dbeafe)!important;color:#1d4ed8!important;font-weight:800!important;border-bottom-color:#3b82f6!important}
.th-wknd{background:#f5f5f7!important;color:#94a3b8!important}
.td-today{background:#eff6ff!important}
.bmr-cell{display:flex;align-items:center;justify-content:center;width:100%;height:100%;cursor:pointer}
.bmr-dot{width:20px;height:20px;border-radius:50%;transition:transform .12s,box-shadow .15s;pointer-events:none;flex-shrink:0}
.bmr-cell:hover .bmr-dot{transform:scale(1.45)}
.d-av{background:linear-gradient(135deg,#4ade80,#16a34a);box-shadow:0 1px 4px rgba(22,163,74,.2);opacity:.32}
.d-bk{background:linear-gradient(135deg,#60a5fa,#1d4ed8);box-shadow:0 2px 8px rgba(29,78,216,.50)}
.d-ci{background:linear-gradient(135deg,#f87171,#b91c1c);box-shadow:0 2px 8px rgba(185,28,28,.50)}
.d-vc{background:linear-gradient(135deg,#fbbf24,#d97706);box-shadow:0 2px 6px rgba(217,119,6,.45)}
.d-oo{background:linear-gradient(135deg,#94a3b8,#475569);box-shadow:0 1px 3px rgba(0,0,0,.12);opacity:.38}
.d-mn{background:linear-gradient(135deg,#c084fc,#7c3aed);box-shadow:0 2px 6px rgba(124,58,237,.4);opacity:.4}
td.bmr-cl{cursor:pointer}
td.bmr-cl:hover{background:#f0f7ff!important}
td.bmr-cl:active{background:#dbeafe!important}
.bmr-footer{display:flex;justify-content:space-between;align-items:center;padding:10px 18px;background:#f8fafc;border-top:1px solid #e2e8f0;flex-wrap:wrap;gap:6px;border-radius:0 0 16px 16px}
.bmr-legend{display:flex;gap:14px;flex-wrap:wrap;align-items:center}
.bmr-leg{display:flex;align-items:center;gap:5px;font-size:11px;color:#475569;font-weight:500}
.bmr-ld{width:10px;height:10px;border-radius:50%;display:inline-block;flex-shrink:0}
.ld-av{background:#16a34a;opacity:.4}.ld-bk{background:#1d4ed8}.ld-ci{background:#b91c1c}.ld-vc{background:#d97706}.ld-oo{background:#64748b;opacity:.5}
.bmr-tip{font-size:10px;color:#94a3b8;letter-spacing:.1px}
.bmr-loading{display:flex;align-items:center;justify-content:center;gap:10px;padding:44px 20px;color:#94a3b8;font-size:13px;background:#fff}
.bmr-spinner{width:18px;height:18px;border:2.5px solid #e2e8f0;border-top-color:#3b82f6;border-radius:50%;animation:bmr-spin .75s linear infinite;flex-shrink:0}
@keyframes bmr-spin{to{transform:rotate(360deg)}}
.bmr-tt{position:fixed;z-index:99999;background:#1e293b;color:#f1f5f9;border-radius:10px;padding:10px 14px;font-size:12px;min-width:200px;max-width:280px;box-shadow:0 8px 30px rgba(0,0,0,.3);pointer-events:none;line-height:1.5}
.bmr-tt-head{font-size:13px;font-weight:700;color:#fff;margin-bottom:6px;border-bottom:1px solid rgba(255,255,255,.12);padding-bottom:5px}
.bmr-tt-row{display:flex;justify-content:space-between;gap:8px;margin-top:3px}
.bmr-tt-lbl{color:rgba(255,255,255,.55);font-size:11px}
.bmr-tt-val{color:#f1f5f9;font-weight:600;font-size:11px}
.bmr-tt-badge{display:inline-block;padding:1px 7px;border-radius:20px;font-size:10px;font-weight:700;margin-top:4px}
.bmr-tt-booked{background:#1d4ed8;color:#fff}
.bmr-tt-checkedin{background:#b91c1c;color:#fff}
.bmr-tt-avail{background:rgba(22,163,74,.3);color:#4ade80}
.bmr-tt-vacant{background:rgba(217,119,6,.3);color:#fbbf24}

script:
var currentMonth=moment();
var _bmrTip=root_element.querySelector('#bmr-tooltip');
function bmrCls(room,res){
  if(res)return res.status==='Checked In'?'d-ci':'d-bk';
  switch(room.status){case 'Occupied':return 'd-ci';case 'Vacant':return 'd-vc';case 'Out of Order':return 'd-oo';case 'Maintenance':return 'd-mn';default:return 'd-av';}
}
function bmrFmt(n){return n!=null?'&#8377; '+parseFloat(n).toLocaleString('en-IN',{minimumFractionDigits:0,maximumFractionDigits:0}):'&#8212;';}
function bmrShowTip(e,room,res){
  if(!_bmrTip)return;
  var h='';
  if(res){
    var badge=res.status==='Checked In'?'bmr-tt-checkedin':'bmr-tt-booked';
    h='<div class="bmr-tt-head">'+frappe.utils.escape_html(room.room_name)+'</div>';
    h+='<div class="bmr-tt-row"><span class="bmr-tt-lbl">Guest</span><span class="bmr-tt-val">'+frappe.utils.escape_html(res.customer||'N/A')+'</span></div>';
    h+='<div class="bmr-tt-row"><span class="bmr-tt-lbl">Check-in</span><span class="bmr-tt-val">'+res.check_in.split(' ')[0]+'</span></div>';
    h+='<div class="bmr-tt-row"><span class="bmr-tt-lbl">Check-out</span><span class="bmr-tt-val">'+res.check_out.split(' ')[0]+'</span></div>';
    if(res.total_nights)h+='<div class="bmr-tt-row"><span class="bmr-tt-lbl">Nights</span><span class="bmr-tt-val">'+res.total_nights+'</span></div>';
    h+='<div class="bmr-tt-row"><span class="bmr-tt-lbl">Total</span><span class="bmr-tt-val">'+bmrFmt(res.grand_total)+'</span></div>';
    h+='<div class="bmr-tt-row"><span class="bmr-tt-lbl">Advance</span><span class="bmr-tt-val">'+bmrFmt(res.advance_amount)+'</span></div>';
    h+='<div class="bmr-tt-row"><span class="bmr-tt-lbl">Balance</span><span class="bmr-tt-val" style="color:'+(parseFloat(res.balance_due||0)>0?'#f87171':'#4ade80')+'">'+bmrFmt(res.balance_due)+'</span></div>';
    h+='<div><span class="bmr-tt-badge '+badge+'">'+frappe.utils.escape_html(res.status)+'</span></div>';
  } else {
    h='<div class="bmr-tt-head">'+frappe.utils.escape_html(room.room_name)+'</div>';
    var badge2=room.status==='Available'?'bmr-tt-avail':room.status==='Vacant'?'bmr-tt-vacant':'';
    h+='<div class="bmr-tt-row"><span class="bmr-tt-lbl">Status</span><span class="bmr-tt-val">'+frappe.utils.escape_html(room.status)+'</span></div>';
    if(room.room_type)h+='<div class="bmr-tt-row"><span class="bmr-tt-lbl">Type</span><span class="bmr-tt-val">'+frappe.utils.escape_html(room.room_type)+'</span></div>';
    if(room.floor)h+='<div class="bmr-tt-row"><span class="bmr-tt-lbl">Floor</span><span class="bmr-tt-val">'+room.floor+'</span></div>';
    if(room.status==='Available')h+='<div style="margin-top:5px;font-size:10px;color:#64748b">Click to create booking</div>';
    if(badge2)h+='<div><span class="bmr-tt-badge '+badge2+'">'+frappe.utils.escape_html(room.status)+'</span></div>';
  }
  _bmrTip.innerHTML=h;
  bmrPosTip(e);
  _bmrTip.style.display='block';
}
function bmrPosTip(e){
  if(!_bmrTip)return;
  var x=e.clientX+14,y=e.clientY+14;
  var tw=_bmrTip.offsetWidth||220,th=_bmrTip.offsetHeight||120;
  if(x+tw>window.innerWidth-10)x=e.clientX-tw-10;
  if(y+th>window.innerHeight-10)y=e.clientY-th-14;
  _bmrTip.style.left=x+'px';
  _bmrTip.style.top=y+'px';
}
function bmrHideTip(){if(_bmrTip)_bmrTip.style.display='none';}
function bmrRender(){
  var m=currentMonth.clone(),days=m.daysInMonth(),from=m.clone().startOf('month').format('YYYY-MM-DD'),to=m.clone().endOf('month').format('YYYY-MM-DD'),today=frappe.datetime.get_today();
  var lbl=root_element.querySelector('#bmr-month-label');if(lbl)lbl.textContent=m.format('MMMM YYYY');
  var grid=root_element.querySelector('#bmr-grid-body');
  if(grid)grid.innerHTML='<div class="bmr-loading"><div class="bmr-spinner"></div><span>Loading rooms…</span></div>';
  Promise.all([
    frappe.call({method:'bookmyroom.book_my_room.page.room_status_dashboard.room_status_dashboard.get_room_status_data',args:{}}),
    frappe.call({method:'bookmyroom.book_my_room.page.room_status_dashboard.room_status_dashboard.get_calendar_data',args:{from_date:from,to_date:to}})
  ]).then(function(r){
    bmrDraw((r[0]&&r[0].message)||[],(r[1]&&r[1].message)||[],m,days,today);
  }).catch(function(e){
    console.error('BMR',e);
    var g=root_element.querySelector('#bmr-grid-body');
    if(g)g.innerHTML='<div class="bmr-loading" style="color:#ef4444">⚠️ Error loading data.</div>';
  });
}
function bmrDraw(rooms,cal,m,days,today){
  var byRoom={};
  cal.forEach(function(r){if(!byRoom[r.room])byRoom[r.room]=[];byRoom[r.room].push(r);});
  var roomMap={};rooms.forEach(function(r){roomMap[r.name]=r;});
  var h='<table class="bmr-table"><thead><tr><th class="bmr-rc">▲ Room</th>';
  for(var d=1;d<=days;d++){
    var dt=m.clone().date(d).format('YYYY-MM-DD'),dow=m.clone().date(d).day(),dl=m.clone().date(d).format('ddd').charAt(0);
    var cls=dt===today?'th-today':dow===0||dow===6?'th-wknd':'';
    h+='<th class="'+cls+'">'+String(d).padStart(2,'0')+'<br><span style="font-weight:400;font-size:9px;opacity:.8">'+dl+'</span></th>';
  }
  h+='</tr></thead><tbody>';
  rooms.forEach(function(room){
    h+='<tr><td class="bmr-rc">'+frappe.utils.escape_html(room.room_name)+'</td>';
    for(var d=1;d<=days;d++){
      var dt=m.clone().date(d).format('YYYY-MM-DD'),res=null,ress=byRoom[room.name]||[];
      for(var i=0;i<ress.length;i++){if(ress[i].check_in.split(' ')[0]<=dt&&ress[i].check_out.split(' ')[0]>dt){res=ress[i];break;}}
      var cls=bmrCls(room,res),resN=res?res.reservation||'':'';
      var tdCls='bmr-cl'+(dt===today?' td-today':'');
      var advance=res?encodeURIComponent(JSON.stringify({customer:res.customer||'',check_in:res.check_in,check_out:res.check_out,status:res.status,grand_total:res.grand_total||0,advance_amount:res.advance_amount||0,balance_due:res.balance_due||0,total_nights:res.total_nights||0})):'';
      h+='<td class="'+tdCls+'" data-room="'+frappe.utils.escape_html(room.name)+'" data-hotel="'+frappe.utils.escape_html(room.hotel||'')+'" data-date="'+dt+'" data-res="'+frappe.utils.escape_html(resN)+'" data-rs="'+frappe.utils.escape_html(room.status)+'" data-rd="'+advance+'">';
      h+='<div class="bmr-cell"><div class="bmr-dot '+cls+'"></div></div></td>';
    }
    h+='</tr>';
  });
  h+='</tbody></table>';
  var el=root_element.querySelector('#bmr-grid-body');
  if(el){
    el.innerHTML=h;
    el.querySelectorAll('td.bmr-cl').forEach(function(td){
      td.addEventListener('mouseenter',function(e){
        var room=roomMap[this.getAttribute('data-room')]||{room_name:this.getAttribute('data-room'),status:this.getAttribute('data-rs')};
        var rd=this.getAttribute('data-rd');
        var res=rd?JSON.parse(decodeURIComponent(rd)):null;
        bmrShowTip(e,room,res);
      });
      td.addEventListener('mousemove',bmrPosTip);
      td.addEventListener('mouseleave',bmrHideTip);
      td.addEventListener('click',function(){
        bmrHideTip();
        var rn=this.getAttribute('data-res'),hotel=this.getAttribute('data-hotel'),date=this.getAttribute('data-date'),rs=this.getAttribute('data-rs'),roomName=this.getAttribute('data-room');
        if(rn){
          frappe.set_route('Form','Room Reservation',rn);
        } else if(rs!=='Out of Order'&&rs!=='Maintenance'){
          var today=frappe.datetime.get_today();
          frappe.call({method:'bookmyroom.book_my_room.doctype.booking_settings.booking_settings.get_booking_settings',callback:function(r){
            var settings=r.message||{};
            if(settings.block_backdated_booking&&date<today){
              frappe.msgprint({title:'Backdated Booking Blocked',message:'Backdated bookings are disabled. Enable them in <b>Booking Settings</b> to proceed.',indicator:'red'});
              return;
            }
            window._bmr_prefill_room=roomName;
            frappe.route_options={hotel:hotel,check_in:date+' 00:00:00',check_out:moment(date).add(1,'day').format('YYYY-MM-DD')+' 00:00:00'};
            frappe.set_route('Form','Room Reservation','new-room-reservation-1');
          }});
        }
      });
    });
  }
}
var _p=root_element.querySelector('#bmr-prev'),_n=root_element.querySelector('#bmr-next');
if(_p)_p.addEventListener('click',function(){currentMonth.subtract(1,'month');bmrRender();});
if(_n)_n.addEventListener('click',function(){currentMonth.add(1,'month');bmrRender();});
bmrRender();
setInterval(bmrRender,60000);
frappe.realtime.on('doc_update',function(d){if(d.doctype==='Room'||d.doctype==='Room Reservation')bmrRender();});
document.addEventListener('visibilitychange',function(){if(!document.hidden)bmrRender();});
